func TestGenerateCard_SkipsUnsupportedRecords(t *testing.T) {
	// Mix of supported (go, ts) and unsupported (unsupported_lang) records.
	records := []domain.CertificationRecord{
		makeCardRecord("go", "a.go", "A", domain.StatusCertified, 0.95),
		makeCardRecord("ts", "b.ts", "B", domain.StatusCertified, 0.85),
		makeCardRecord("unsupported_lang", "c.xyz", "C", domain.StatusCertified, 0.99),
	}

	c := report.GenerateCard(records, "test/repo", "abc123", time.Now())

	// TotalUnits should only count supported records (2 of 3)
	if c.TotalUnits != 2 {
		t.Errorf("total = %d, want 2 (unsupported skipped)", c.TotalUnits)
	}
	// Passing should only count supported records
	if c.Passing != 2 {
		t.Errorf("passing = %d, want 2", c.Passing)
	}
	// OverallScore should only use supported records: (0.95+0.85)/2 = 0.90
	expectedScore := (0.95 + 0.85) / 2.0
	if c.OverallScore != expectedScore {
		t.Errorf("overall score = %f, want %f", c.OverallScore, expectedScore)
	}
	// PassRate should use counted denominator: 2/2 = 1.0
	if c.PassRate != 1.0 {
		t.Errorf("pass rate = %f, want 1.0", c.PassRate)
	}
}

