	// Verify the supported ones are go and ts
	langs := make(map[string]bool)
	for _, r := range supported {
		langs[r.UnitID.Language()] = true
	}
	if !langs["go"] || !langs["ts"] {
		t.Errorf("expected supported languages go and ts, got %v", langs)
